import { type PropsWithChildren, type HTMLAttributes } from 'react';

import { container } from './TooltipSymbolContent.sty.js';
import { SymbolAtom } from '../../../tooltip-atoms/components/SymbolAtom.js';

export const TooltipSymbolContent = (
  props: PropsWithChildren<HTMLAttributes<HTMLDivElement>>,
) => {
  const { children, ...rest } = props;

  return (
    <div className={container} {...rest}>
      <SymbolAtom>{children}</SymbolAtom>
    </div>
  );
};

TooltipSymbolContent['displayName'] = 'TooltipSymbolContent';
